template <class T>
class Node {
public:
    T data;
    Node<T>* next;
    Node<T>* prev;

    Node(T value) {
        data = value;
        next = nullptr;
        prev = nullptr;
    }
};

template <class T>
class Deque {
private:
    Node<T>* front;
    Node<T>* back;

public:
    Deque() {
        front = nullptr;
        back = nullptr;
    }

    void pushFront(T val) {
        Node<T>* node = new Node<T>(val);
        if (front == nullptr) {
            front = back = node;
            return;
        }

        node->next = front;
        front->prev = node;
        front = node;
    }

    void popBack() {
        if (back == nullptr) {
            return;
        }

        Node<T>* temp = back;
        if (front == back) {
            front = back = nullptr;
        } else {
            back = back->prev;
            back->next = nullptr;
        }
        delete temp;
    }

    void moveToFront(int pos) {
        if (front == nullptr || pos <= 0) {
            return;
        }

        Node<T>* current = front;
        for (int i = 0; current != nullptr && i < pos; i++) {
            current = current->next;
        }

        if (current == nullptr || current == front) {
            return;
        }

        if (current == back) {
            back = current->prev;
        }

        if (current->prev != nullptr) {
            current->prev->next = current->next;
        }
        if (current->next != nullptr) {
            current->next->prev = current->prev;
        }

        current->prev = nullptr;
        current->next = front;
        front->prev = current;
        front = current;
    }
};

#include <iostream>
#include <unordered_map>
#include <vector>
#include <algorithm>
#include <string>
using namespace std;

unordered_map<int, int> productSales;

void add_transaction(string customer_name, int product_id) {
    productSales[product_id]++;
}

int get_product_sales_count(int product_id) {
    if (productSales.find(product_id) == productSales.end()) {
        return 0;
    }
    return productSales[product_id];
}

void print_top_products_ids() {
    vector<pair<int, int>> items;

    for (auto item : productSales) {
        items.push_back({item.first, item.second});
    }

    sort(items.begin(), items.end(), [](const pair<int, int>& a, const pair<int, int>& b) {
        if (a.second == b.second) {
            return a.first < b.first;
        }
        return a.second > b.second;
    });

    int limit = min(5, (int)items.size());
    for (int i = 0; i < limit; i++) {
        cout << items[i].first << endl;
    }
}
